export enum TipoTransacao {
  RECEITA = 'RECEITA',
  DESPESA = 'DESPESA'
}

export enum Categoria {
  SALARIO = 'Salário',
  INVESTIMENTO = 'Investimento',
  ALIMENTACAO = 'Alimentação',
  MORADIA = 'Moradia',
  TRANSPORTE = 'Transporte',
  LAZER = 'Lazer',
  SAUDE = 'Saúde',
  SERVICOS = 'Serviços',
  OUTROS = 'Outros'
}

export interface Transacao {
  id: string;
  descricao: string;
  valor: number;
  tipo: TipoTransacao;
  categoria: Categoria;
  data: string; // ISO String
}

export interface Usuario {
  id: string;
  nome: string;
  email: string;
  salarioMensal: number;
}

export interface AnaliseIA {
  sugestoes: string[];
  auditoria: string;
  projecaoInvestimento: string;
  risco: 'Baixo' | 'Médio' | 'Alto';
}

import { GoogleGenAI, Type } from "@google/genai";
import { Transacao, AnaliseIA } from "../tipos";

// Inicializa o cliente Gemini com a chave de API segura do ambiente
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analisarFinancas = async (transacoes: Transacao[], salario: number): Promise<AnaliseIA> => {
  try {
    const dadosFinanceiros = JSON.stringify({
      salario_mensal: salario,
      historico_transacoes: transacoes.map(t => ({
        ...t,
        valor: t.tipo === 'DESPESA' ? -t.valor : t.valor
      }))
    });

    const prompt = `
      Atue como um Consultor Financeiro Sênior e Auditor. Analise os seguintes dados financeiros brutos.
      Identifique padrões de gastos, desperdícios, e sugira otimizações agressivas para retorno financeiro.
      Calcule potenciais de investimento se o usuário seguir as dicas.

      Dados: ${dadosFinanceiros}
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "Você é um especialista em finanças pessoais focado em acumulação de riqueza e eficiência. Seja direto e analítico.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sugestoes: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Lista de 3 a 5 ações práticas para economizar ou investir."
            },
            auditoria: {
              type: Type.STRING,
              description: "Um resumo crítico sobre o comportamento financeiro atual."
            },
            projecaoInvestimento: {
              type: Type.STRING,
              description: "Projeção de quanto o usuário teria em 1 ano se aplicasse as economias sugeridas."
            },
            risco: {
              type: Type.STRING,
              enum: ["Baixo", "Médio", "Alto"],
              description: "Nível de risco da saúde financeira atual."
            }
          },
          required: ["sugestoes", "auditoria", "projecaoInvestimento", "risco"]
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as AnaliseIA;
    }

    throw new Error("Não foi possível gerar a análise.");
  } catch (error) {
    console.error("Erro ao consultar Gemini:", error);
    return {
      sugestoes: ["Erro ao conectar com a IA. Tente novamente mais tarde."],
      auditoria: "Indisponível",
      projecaoInvestimento: "Indisponível",
      risco: "Baixo"
    };
  }
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Transacao, TipoTransacao, Categoria, Usuario } from '../tipos';

interface ContextoFinanceiroProps {
  usuario: Usuario | null;
  transacoes: Transacao[];
  login: (nome: string, email: string, salario: number) => void;
  logout: () => void;
  adicionarTransacao: (transacao: Omit<Transacao, 'id'>) => void;
  removerTransacao: (id: string) => void;
  saldoTotal: number;
  receitaTotal: number;
  despesaTotal: number;
}

const ContextoFinanceiro = createContext<ContextoFinanceiroProps | undefined>(undefined);

export const ProvedorFinanceiro: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [usuario, setUsuario] = useState<Usuario | null>(() => {
    const salvo = localStorage.getItem('fin_usuario');
    return salvo ? JSON.parse(salvo) : null;
  });

  const [transacoes, setTransacoes] = useState<Transacao[]>(() => {
    const salvo = localStorage.getItem('fin_transacoes');
    return salvo ? JSON.parse(salvo) : [];
  });

  // Persistência
  useEffect(() => {
    if (usuario) localStorage.setItem('fin_usuario', JSON.stringify(usuario));
    else localStorage.removeItem('fin_usuario');
  }, [usuario]);

  useEffect(() => {
    localStorage.setItem('fin_transacoes', JSON.stringify(transacoes));
  }, [transacoes]);

  const login = (nome: string, email: string, salarioMensal: number) => {
    // Simulação de login seguro - Em prod, isso viria de um backend com JWT
    const novoUsuario: Usuario = {
      id: crypto.randomUUID(),
      nome,
      email,
      salarioMensal
    };
    setUsuario(novoUsuario);
  };

  const logout = () => {
    setUsuario(null);
    setTransacoes([]); // Limpa dados da sessão visual (storage mantido por opção, ou limpar tudo)
    localStorage.removeItem('fin_usuario');
  };

  const adicionarTransacao = (dados: Omit<Transacao, 'id'>) => {
    const nova: Transacao = {
      id: crypto.randomUUID(),
      ...dados
    };
    setTransacoes(prev => [nova, ...prev]);
  };

  const removerTransacao = (id: string) => {
    setTransacoes(prev => prev.filter(t => t.id !== id));
  };

  const receitaTotal = transacoes
    .filter(t => t.tipo === TipoTransacao.RECEITA)
    .reduce((acc, curr) => acc + curr.valor, 0);

  const despesaTotal = transacoes
    .filter(t => t.tipo === TipoTransacao.DESPESA)
    .reduce((acc, curr) => acc + curr.valor, 0);

  const saldoTotal = receitaTotal - despesaTotal;

  return (
    <ContextoFinanceiro.Provider value={{
      usuario,
      transacoes,
      login,
      logout,
      adicionarTransacao,
      removerTransacao,
      saldoTotal,
      receitaTotal,
      despesaTotal
    }}>
      {children}
    </ContextoFinanceiro.Provider>
  );
};

export const useFinanceiro = () => {
  const context = useContext(ContextoFinanceiro);
  if (!context) throw new Error('useFinanceiro deve ser usado dentro de ProvedorFinanceiro');
  return context;
};

import React from 'react';

interface BotaoProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variante?: 'primario' | 'secundario' | 'perigo' | 'fantasma';
  carregando?: boolean;
}

export const Botao: React.FC<BotaoProps> = ({ 
  children, 
  variante = 'primario', 
  carregando = false, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyles = "px-4 py-2 rounded-lg font-medium transition-all duration-200 flex items-center justify-center gap-2 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 disabled:opacity-50 disabled:cursor-not-allowed";

  const variantes = {
    primario: "bg-emerald-500 hover:bg-emerald-600 text-white focus:ring-emerald-500 shadow-lg shadow-emerald-500/20",
    secundario: "bg-slate-700 hover:bg-slate-600 text-slate-100 focus:ring-slate-500 border border-slate-600",
    perigo: "bg-rose-500 hover:bg-rose-600 text-white focus:ring-rose-500 shadow-lg shadow-rose-500/20",
    fantasma: "bg-transparent hover:bg-slate-800 text-slate-400 hover:text-white"
  };

  return (
    <button 
      className={`${baseStyles} ${variantes[variante]} ${className}`}
      disabled={disabled || carregando}
      {...props}
    >
      {carregando ? (
        <>
          <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processando...
        </>
      ) : children}
    </button>
  );
};

