                <Plus className="w-4 h-4 mr-1" /> Adicionar
              </Botao>
            </form>
          </div>

          {/* Charts */}
          <div className="lg:col-span-2 bg-slate-800 p-6 rounded-xl border border-slate-700 flex flex-col gap-8">
             <div>
               <h3 className="text-lg font-semibold text-white mb-4">Distribuição de Despesas</h3>
               <div className="h-64 w-full">
                 <ResponsiveContainer width="100%" height="100%">
                   <PieChart>
                     <Pie
                       data={dadosGraficoPizza}
                       cx="50%"
                       cy="50%"
                       innerRadius={60}
                       outerRadius={80}
                       paddingAngle={5}
                       dataKey="value"
                     >
                       {dadosGraficoPizza.map((entry, index) => (
                         <Cell key={`cell-${index}`} fill={CORES_GRAFICO[index % CORES_GRAFICO.length]} />
                       ))}
                     </Pie>
                     <TooltipRecharts 
                        contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f8fafc' }}
                        itemStyle={{ color: '#f8fafc' }}
                     />
                   </PieChart>
                 </ResponsiveContainer>
               </div>
             </div>
          </div>
        </div>

        {/* Transaction Table */}
        <div className="bg-slate-800 rounded-xl border border-slate-700 overflow-hidden">
          <div className="p-6 border-b border-slate-700 flex flex-wrap gap-4 justify-between items-center">
            <h3 className="text-lg font-semibold text-white">Histórico de Transações</h3>
            <div className="flex items-center gap-2">
              <Filter className="w-4 h-4 text-slate-400" />
              <select 
                className="bg-slate-900 border border-slate-700 text-slate-300 text-sm rounded-lg focus:ring-emerald-500 focus:border-emerald-500 p-2"
                value={filtroCategoria}
                onChange={(e) => setFiltroCategoria(e.target.value)}
              >
                <option value="TODAS">Todas Categorias</option>
                {Object.values(Categoria).map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-sm text-left text-slate-400">
              <thead className="text-xs text-slate-400 uppercase bg-slate-900/50">
                <tr>
                  <th scope="col" className="px-6 py-3">Descrição</th>
                  <th scope="col" className="px-6 py-3">Categoria</th>
                  <th scope="col" className="px-6 py-3">Data</th>
                  <th scope="col" className="px-6 py-3">Valor</th>
                  <th scope="col" className="px-6 py-3 text-right">Ações</th>
                </tr>
              </thead>
              <tbody>
                {dadosFiltrados.length === 0 ? (
                  <tr>
                    <td colSpan={5} className="px-6 py-8 text-center text-slate-500">
                      Nenhuma transação encontrada.
                    </td>
                  </tr>
                ) : (
                  dadosFiltrados.map((transacao) => (
                    <tr key={transacao.id} className="bg-slate-800 border-b border-slate-700 hover:bg-slate-700/50 transition-colors">
                      <td className="px-6 py-4 font-medium text-white">{transacao.descricao}</td>
                      <td className="px-6 py-4">
                        <span className="bg-slate-700 text-slate-300 text-xs font-medium px-2.5 py-0.5 rounded border border-slate-600">
                          {transacao.categoria}
                        </span>
                      </td>
                      <td className="px-6 py-4">{new Date(transacao.data).toLocaleDateString()}</td>
                      <td className={`px-6 py-4 font-bold ${
                        transacao.tipo === TipoTransacao.RECEITA ? 'text-emerald-400' : 'text-rose-400'
                      }`}>
                        {transacao.tipo === TipoTransacao.DESPESA ? '-' : '+'} 
                        {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(transacao.valor)}
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button 
                          onClick={() => removerTransacao(transacao.id)}
                          className="text-slate-500 hover:text-rose-500 transition-colors p-1"
                          title="Remover"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>
      </main>
    </div>
  );
};

import React from 'react';
import { ProvedorFinanceiro, useFinanceiro } from './contextos/ContextoFinanceiro';
import { PaginaLogin } from './paginas/Login';
import { PaginaPainel } from './paginas/Painel';

// Componente roteador interno simples para o SPA
const Roteador: React.FC = () => {
  const { usuario } = useFinanceiro();

  // Renderização condicional baseada na autenticação
  return usuario ? <PaginaPainel /> : <PaginaLogin />;
};

const App: React.FC = () => {
  return (
    <ProvedorFinanceiro>
      <Roteador />
    </ProvedorFinanceiro>
  );
};

export default App;
